            ctx.fillStyle = '#4fd1c5';
            ctx.fillText(`最高分: ${highScore}`, canvas.width / 2, 380);

            if (playerScore > aiScore) {
                ctx.fillStyle = '#4fd1c5';
                ctx.fillText('你赢了！', canvas.width / 2, 440);
